1	<script lang="ts">
2		import type { LayoutData } from './$types';
3		import type { Snippet } from 'svelte';
4		import { goto, invalidateAll } from '$app/navigation';
5		import { page } from '$app/stores';
6		import { createClient } from '$lib/gql/client';
7		import { gql } from 'graphql-request';
8		import BeadForm from '$lib/components/BeadForm.svelte';
9		import { subscribeBeadLifecycle } from '$lib/gql/subscriptions';
10	
11		const BEADS_QUERY = gql`
12			query BeadsByProject(
13				$projectID: String!
14				$first: Int
15				$after: String
16				$status: String
17				$label: String
18				$search: String
19			) {
20				beadsByProject(
21					projectID: $projectID
22					first: $first
23					after: $after
24					status: $status
25					label: $label
26					search: $search
27				) {
28					edges {
29						node {
30							id
31							title
32							status
33							priority
34							owner
35							updatedAt
36							labels
37						}
38						cursor
39					}
40					pageInfo {
41						hasNextPage
42						endCursor
43					}
44					totalCount
45				}
46			}
47		`;
48	
49		interface BeadNode {
50			id: string;
51			title: string;
52			status: string;
53			priority: number;
54			owner: string | null;
55			updatedAt: string;
56			labels: string[] | null;
57		}
58	
59		interface BeadEdge {
60			node: BeadNode;
61			cursor: string;
62		}
63	
64		interface PageInfo {
65			hasNextPage: boolean;
66			endCursor: string | null;
67		}
68	
69		interface BeadsResult {
70			beadsByProject: {
71				edges: BeadEdge[];
72				pageInfo: PageInfo;
73				totalCount: number;
74			};
75		}
76	
77		const STATUS_OPTIONS = ['open', 'ready', 'in-progress', 'closed', 'blocked'];
78		const PRIORITY_OPTIONS = [0, 1, 2, 3, 4];
79	
80		let { data, children }: { data: LayoutData; children: Snippet } = $props();
81	
82		// Extra edges accumulated via "load more" (reset when filter key changes)
83		let appendedEdges = $state<BeadEdge[]>([]);
84		let appendedPageInfo = $state<PageInfo | null>(null);
85		let loadingMore = $state(false);
86		let showCreateForm = $state(false);
87		let prioritySortAsc = $derived(data.activeSort !== 'priority-desc');
88	
89		// Live status overrides from beadLifecycle subscription (beadID -> status)
90		let liveStatusOverrides = $state<Map<string, string>>(new Map());
91	
92		// Subscribe to bead lifecycle events while the page is open
93		$effect(() => {
94			const pid = data.projectId;
95			liveStatusOverrides = new Map();
96			const dispose = subscribeBeadLifecycle(pid, (evt) => {
97				if (evt.kind === 'status_changed' && evt.summary) {
98					const match = evt.summary.match(/status changed from \S+ to (\S+)/);
99					if (match) {
100						const next = new Map(liveStatusOverrides);
101						next.set(evt.beadID, match[1]);
102						liveStatusOverrides = next;
103					}
104				}
105			});
106			return dispose;
107		});
108	
109		// Local search input state (drives URL via debounce)
110		let searchInput = $state(data.activeSearch ?? '');
111	
112		// Debounce: update URL ?q= 200ms after user stops typing
113		let debounceTimer: ReturnType<typeof setTimeout> | null = null;
114		$effect(() => {
115			const val = searchInput;
116			if (debounceTimer) clearTimeout(debounceTimer);
117			debounceTimer = setTimeout(() => {
118				// Skip if the URL already reflects the current input value
119				const currentQ = $page.url.searchParams.get('q') ?? '';
120				if (val === currentQ) return;
121				const params = new URLSearchParams($page.url.searchParams);
122				if (val) {
123					params.set('q', val);
124				} else {
125					params.delete('q');
126				}
127				params.delete('after');
128				const search = params.toString();
129				// Preserve beadId in path if panel is open
130				const pathname = $page.url.pathname;
131				goto(search ? `${pathname}?${search}` : pathname, { replaceState: true });
132			}, 200);
133		});
134	
135		// Sync searchInput when URL changes (e.g. back/forward navigation)
136		$effect(() => {
137			searchInput = data.activeSearch ?? '';
138		});
139	
140		// Track the active filter combo so we can reset appended pages on change
141		let filterKey = $derived(
142			`${data.activeStatus}::${data.activePriority}::${data.activeLabel}::${data.activeSearch}`
143		);
144		let prevFilterKey = $state('');
145		$effect(() => {
146			if (filterKey !== prevFilterKey) {
147				prevFilterKey = filterKey;
148				appendedEdges = [];
149				appendedPageInfo = null;
150			}
151		});
152	
153		let edges = $derived([...data.beads.edges, ...appendedEdges]);
154		let filteredEdges = $derived(
155			edges.filter((edge) => {
156				const activeStatus = liveStatusOverrides.get(edge.node.id) ?? edge.node.status;
157				const labels = edge.node.labels ?? [];
158				const search = data.activeSearch?.toLowerCase();
159				return (
160					(!data.activeStatus || activeStatus === data.activeStatus) &&
161					(!data.activePriority || String(edge.node.priority) === data.activePriority) &&
162					(!data.activeLabel || labels.includes(data.activeLabel)) &&
163					(!search ||
164						edge.node.title.toLowerCase().includes(search) ||
165						edge.node.id.toLowerCase().includes(search) ||
166						labels.some((label) => label.toLowerCase().includes(search)))
167				);
168			})
169		);
170		let sortedEdges = $derived(
171			[...filteredEdges].sort((a, b) =>
172				prioritySortAsc ? a.node.priority - b.node.priority : b.node.priority - a.node.priority
173			)
174		);
175		let pageInfo = $derived<PageInfo>(appendedPageInfo ?? data.beads.pageInfo);
176		let totalCount = $derived(data.beads.totalCount);
177	
178		// Derive all unique labels from current result set
179		let allLabels = $derived(Array.from(new Set(edges.flatMap((e) => e.node.labels ?? []))).sort());
180		let hasActiveFilters = $derived(
181			Boolean(data.activeStatus || data.activePriority || data.activeLabel || data.activeSearch)
182		);
183	
184		// The currently open bead (from child route params)
185		let activeBead = $derived(($page.params as Record<string, string>)['beadId'] ?? null);
186	
187		function setFilter(key: 'status' | 'priority' | 'labels', value: string | null) {
188			const params = new URLSearchParams($page.url.searchParams);
189			if (value === null) {
190				params.delete(key);
191			} else {
192				params.set(key, value);
193			}
194			if (key === 'labels') {
195				params.delete('label');
196			}
197			// Changing filters resets pagination
198			params.delete('after');
199			const search = params.toString();
200			// Stay on same path (either /beads or /beads/[beadId])
201			goto(search ? `?${search}` : $page.url.pathname, { replaceState: true });
202		}
203	
204		function toggleStatus(status: string) {
205			setFilter('status', data.activeStatus === status ? null : status);
206		}
207	
208		function togglePriority(priority: number) {
209			const priorityValue = String(priority);
210			setFilter('priority', data.activePriority === priorityValue ? null : priorityValue);
211		}
212	
213		function togglePrioritySort() {
214			const params = new URLSearchParams($page.url.searchParams);
215			const nextSort = prioritySortAsc ? 'priority-desc' : 'priority-asc';
216			if (nextSort === 'priority-asc') {
217				params.delete('sort');
218			} else {
219				params.set('sort', nextSort);
220			}
221			const search = params.toString();
222			goto(search ? `?${search}` : $page.url.pathname, { replaceState: true });
223		}
224	
225		function toggleLabel(label: string) {
226			setFilter('labels', data.activeLabel === label ? null : label);
227		}
228	
229		function clearFilters() {
230			const params = new URLSearchParams($page.url.searchParams);
231			params.delete('status');
232			params.delete('priority');
233			params.delete('label');
234			params.delete('labels');
235			params.delete('q');
236			params.delete('after');
237			searchInput = '';
238			const search = params.toString();
239			goto(search ? `?${search}` : $page.url.pathname, { replaceState: true });
240		}
241	
242		async function loadMore() {
243			if (!pageInfo.hasNextPage || loadingMore) return;
244			loadingMore = true;
245			try {
246				const client = createClient();
247				const result = await client.request<BeadsResult>(BEADS_QUERY, {
248					projectID: data.projectId,
249					first: 10,
250					after: pageInfo.endCursor,
251					status: data.activeStatus ?? undefined,
252					label: data.activeLabel ?? undefined,
253					search: data.activeSearch ?? undefined
254				});
255				appendedEdges = [...appendedEdges, ...result.beadsByProject.edges];
256				appendedPageInfo = result.beadsByProject.pageInfo;
257			} finally {
258				loadingMore = false;
259			}
260		}
261	
262		function openBead(beadId: string) {
263			const p = $page.params as Record<string, string>;
264			const searchStr = $page.url.searchParams.toString();
265			const beadPath = `/nodes/${p['nodeId']}/projects/${p['projectId']}/beads/${beadId}`;
266			goto(searchStr ? `${beadPath}?${searchStr}` : beadPath);
267		}
268	
269		function statusBadgeClass(status: string): string {
270			switch (status) {
271				case 'open':
272					return 'badge-status-open';
273				case 'in-progress':
274					return 'badge-status-in-progress';
275				case 'closed':
276					return 'badge-status-closed';
277				case 'blocked':
278					return 'badge-status-blocked';
279				case 'running':
280					return 'badge-status-running';
281				case 'completed':
282					return 'badge-status-completed';
283				case 'failed':
284					return 'badge-status-failed';
285				default:
286					return 'badge-status-neutral';
287			}
288		}
289	
290		function chipClass(active: boolean): string {
291			return active
292				? 'rounded-sm border px-3 py-1 text-xs font-medium border-accent-lever bg-accent-lever/10 text-accent-lever dark:border-dark-accent-lever dark:bg-dark-accent-lever/20 dark:text-dark-accent-lever'
293				: 'rounded-sm border px-3 py-1 text-xs font-medium border-border-line bg-bg-elevated text-fg-ink hover:border-fg-muted hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface';
294		}
295	
296		function priorityLabel(priority: number): string {
297			return `P${priority}`;
298		}
299	
300		function priorityClass(priority: number): string {
301			return `text-priority-p${priority}`;
302		}
303	</script>
304	
305	<div class="min-h-full space-y-4 bg-bg-canvas dark:bg-dark-bg-canvas">
306		<div class="flex items-center justify-between">
307			<h1 class="text-xl font-semibold text-fg-ink dark:text-dark-fg-ink">Beads</h1>
308			<div class="flex items-center gap-3">
309				<span class="text-sm text-fg-muted dark:text-dark-fg-muted">
310					{sortedEdges.length} of {totalCount}
311				</span>
312				<button
313					onclick={() => (showCreateForm = true)}
314					class="rounded-sm bg-accent-lever px-3 py-1.5 text-sm font-medium text-white hover:bg-accent-lever/90"
315				>
316					New bead
317				</button>
318			</div>
319		</div>
320	
321		<!-- Search input -->
322		<div class="relative">
323			<input
324				type="search"
325				bind:value={searchInput}
326				placeholder="Search beads…"
327				class="w-full rounded-none border border-border-line bg-bg-elevated px-3 py-2 text-sm text-fg-ink placeholder-fg-muted focus:border-accent-lever focus:ring-1 focus:ring-accent-lever focus:outline-none dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:placeholder-dark-fg-muted dark:focus:border-dark-accent-lever"
328			/>
329		</div>
330	
331		<!-- Status filter chips -->
332		<div class="flex flex-wrap gap-2">
333			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Status:</span>
334			{#each STATUS_OPTIONS as status}
335				<button
336					type="button"
337					aria-pressed={data.activeStatus === status}
338					class={chipClass(data.activeStatus === status)}
339					onclick={() => toggleStatus(status)}
340				>
341					{status}
342				</button>
343			{/each}
344			{#if data.activeStatus}
345				<button
346					type="button"
347					class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1 text-xs text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
348					onclick={() => setFilter('status', null)}
349				>
350					clear
351				</button>
352			{/if}
353		</div>
354	
355		<!-- Priority filter chips -->
356		<div class="flex flex-wrap gap-2">
357			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Priority:</span>
358			{#each PRIORITY_OPTIONS as priority}
359				<button
360					type="button"
361					aria-pressed={data.activePriority === String(priority)}
362					class={chipClass(data.activePriority === String(priority))}
363					onclick={() => togglePriority(priority)}
364				>
365					{priorityLabel(priority)}
366				</button>
367			{/each}
368			{#if data.activePriority}
369				<button
370					type="button"
371					class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1 text-xs text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
372					onclick={() => setFilter('priority', null)}
373				>
374					clear
375				</button>
376			{/if}
377		</div>
378	
379		<!-- Label filter chips (only shown when labels exist in current result) -->
380		{#if allLabels.length > 0}
381			<div class="flex flex-wrap gap-2">
382				<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Labels:</span>
383				{#each allLabels as label}
384					<button
385						type="button"
386						aria-pressed={data.activeLabel === label}
387						class={chipClass(data.activeLabel === label)}
388						onclick={() => toggleLabel(label)}
389					>
390						{label}
391					</button>
392				{/each}
393				{#if data.activeLabel}
394					<button
395						type="button"
396						class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1 text-xs text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
397						onclick={() => setFilter('labels', null)}
398					>
399						clear
400					</button>
401				{/if}
402			</div>
403		{/if}
404	
405		<div class="overflow-hidden border border-border-line bg-bg-elevated dark:border-dark-border-line dark:bg-dark-bg-elevated">
406			<table class="w-full border-collapse text-sm">
407				<thead>
408					<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
409						<th class="px-4 py-3 text-left font-medium text-fg-muted dark:text-dark-fg-muted">ID</th>
410						<th class="px-4 py-3 text-left font-medium text-fg-muted dark:text-dark-fg-muted">Title</th>
411						<th class="px-4 py-3 text-left font-medium text-fg-muted dark:text-dark-fg-muted">Status</th>
412						<th class="px-4 py-3 text-right font-medium text-fg-muted dark:text-dark-fg-muted">
413							<button
414								type="button"
415								aria-label="Sort by priority"
416								class="ml-auto inline-flex items-center gap-1 hover:text-fg-ink dark:hover:text-dark-fg-ink"
417								onclick={togglePrioritySort}
418							>
419								Priority
420								<span aria-hidden="true">{prioritySortAsc ? '↑' : '↓'}</span>
421							</button>
422						</th>
423						<th class="px-4 py-3 text-left font-medium text-fg-muted dark:text-dark-fg-muted">Owner</th>
424						<th class="px-4 py-3 text-left font-medium text-fg-muted dark:text-dark-fg-muted">Updated</th>
425					</tr>
426				</thead>
427				<tbody>
428					{#each sortedEdges as edge (edge.node.id)}
429						<tr
430							data-testid="bead-row"
431							data-priority={edge.node.priority}
432							onclick={() => openBead(edge.node.id)}
433							class="cursor-pointer border-b border-border-line last:border-0 hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface {activeBead ===
434							edge.node.id
435								? 'bg-accent-lever/10 dark:bg-dark-accent-lever/10'
436								: ''}"
437						>
438							<td class="px-4 py-3 font-mono text-xs text-lever">
439								{edge.node.id}
440							</td>
441							<td class="px-4 py-3 text-fg-ink dark:text-dark-fg-ink">
442								{edge.node.title}
443								{#if edge.node.labels?.length}
444									<div class="mt-2 flex flex-wrap gap-1">
445										{#each edge.node.labels as label}
446											<button
447												type="button"
448												data-testid="label-chip"
449												aria-pressed={data.activeLabel === label}
450												class={chipClass(data.activeLabel === label)}
451												onclick={(event) => {
452													event.stopPropagation();
453													toggleLabel(label);
454												}}
455											>
456												{label}
457											</button>
458										{/each}
459									</div>
460								{/if}
461							</td>
462							<td class="px-4 py-3">
463								<span
464									class="inline-block border px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide {statusBadgeClass(
465										liveStatusOverrides.get(edge.node.id) ?? edge.node.status
466									)}"
467								>
468									{liveStatusOverrides.get(edge.node.id) ?? edge.node.status}
469								</span>
470							</td>
471							<td class="px-4 py-3 text-right font-mono text-xs font-medium {priorityClass(edge.node.priority)}">
472								{priorityLabel(edge.node.priority)}
473							</td>
474							<td class="px-4 py-3 text-fg-muted dark:text-dark-fg-muted">
475								{edge.node.owner ?? '—'}
476							</td>
477							<td class="px-4 py-3 text-xs text-fg-muted dark:text-dark-fg-muted">
478								{new Date(edge.node.updatedAt).toLocaleDateString()}
479							</td>
480						</tr>
481					{/each}
482					{#if sortedEdges.length === 0}
483						<tr>
484							<td colspan="6" class="px-4 py-8 text-center text-fg-muted dark:text-dark-fg-muted">
485								{#if hasActiveFilters}
486									<div class="space-y-3">
487										<p>No beads match the current filters.</p>
488										<button
489											type="button"
490											class="rounded-sm border border-border-line bg-bg-elevated px-3 py-1.5 text-sm text-fg-ink hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
491											onclick={clearFilters}
492										>
493											Clear filters
494										</button>
495									</div>
496								{:else}
497									No beads found.
498								{/if}
499							</td>
500						</tr>
501					{/if}
502				</tbody>
503			</table>
504		</div>
505	
506		{#if pageInfo.hasNextPage}
507			<div class="flex justify-center">
508				<button
509					onclick={loadMore}
510					disabled={loadingMore}
511					class="rounded-sm border border-border-line bg-bg-elevated px-4 py-2 text-sm text-fg-ink hover:bg-bg-surface disabled:cursor-not-allowed disabled:opacity-50 dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:hover:bg-dark-bg-surface"
512				>
513					{loadingMore ? 'Loading…' : 'Load more'}
514				</button>
515			</div>
516		{/if}
517	</div>
518	
519	{@render children()}
520	
521	{#if showCreateForm}
522		<!-- Backdrop -->
523		<div
524			class="fixed inset-0 z-40 bg-black/20 dark:bg-black/40"
525			onclick={() => (showCreateForm = false)}
526			role="button"
527			tabindex="-1"
528			aria-label="Close"
529			onkeydown={(e) => e.key === 'Escape' && (showCreateForm = false)}
530		></div>
531	
532		<!-- Create form panel -->
533		<div
534			class="fixed top-0 right-0 z-50 flex h-full w-full max-w-xl flex-col bg-bg-elevated shadow-xl dark:bg-dark-bg-elevated"
535			style="max-width: 36rem;"
536		>
537			<div
538				class="flex shrink-0 items-center justify-between border-b border-border-line px-6 py-4 dark:border-dark-border-line"
539			>
540				<h2 class="text-base font-semibold text-fg-ink dark:text-dark-fg-ink">New bead</h2>
541			</div>
542			<div class="flex-1 overflow-auto p-6">
543				<BeadForm
544					onSuccess={async (newBead) => {
545						showCreateForm = false;
546						await invalidateAll();
547						const p = $page.params as Record<string, string>;
548						const searchStr = $page.url.searchParams.toString();
549						const beadPath = `/nodes/${p['nodeId']}/projects/${p['projectId']}/beads/${newBead.id}`;
550						goto(searchStr ? `${beadPath}?${searchStr}` : beadPath);
551					}}
552					onCancel={() => (showCreateForm = false)}
553				/>
554			</div>
555		</div>
556	{/if}
